"""测试增强指纹 (nc, w, h, xMin) 是否能区分所有10个glyph"""
import base64
from io import BytesIO
from fontTools.ttLib import TTFont

font1_b64 = ""

f_bytes = base64.b64decode(font1_b64)
font = TTFont(BytesIO(f_bytes))
cmap = font.getBestCmap()
glyf = font["glyf"]

print("Full glyph features (nc, w, h, xMin, coords_count):")
header = "{:<6} {:<4} {:<6} {:<6} {:<8} {:<8} {:<8} {:<8} {:<8}".format(
    "Char", "nc", "w", "h", "xMin", "yMin", "xMax", "yMax", "coords")
print(header)
print("-" * len(header))

fingerprints = {}
for char in "0123456789":
    gn = cmap.get(ord(char))
    if gn:
        g = glyf[gn]
        coords, _, _ = g.getCoordinates(glyf) if hasattr(g, "getCoordinates") else (None, None, None)
        nc = g.numberOfContours
        w = g.xMax - g.xMin
        h = g.yMax - g.yMin
        n_coords = len(coords) if coords is not None else 0
        print("{:<6} {:<4} {:<6} {:<6} {:<8} {:<8} {:<8} {:<8} {:<8}".format(
            char, nc, w, h, g.xMin, g.yMin, g.xMax, g.yMax, n_coords))
        # Test: use (nc, w, h, xMin) as fingerprint
        finger4 = (nc, w, h, g.xMin)
        if finger4 in fingerprints:
            print("  ** DUPLICATE with char {} **".format(fingerprints[finger4]))
        fingerprints[finger4] = char

font.close()

print()
print("Unique 4-feature fingerprints:", len(fingerprints))
if len(fingerprints) == 10:
    print("SUCCESS: (nc, w, h, xMin) uniquely identifies all 10 glyphs!")
else:
    print("Need more features, only {} unique fingerprints".format(len(fingerprints)))
    # Try adding coords_count
    print("Check if coords_count helps...")
